23. });
24. 
25. app.post('/api/ai_geojson', async (req, res) => {
26.     const { prompt } = req.body;
27.     const apiKey = process.env.OPENAI_API_KEY;
28. 
29.     try {
30.         const response = await fetch('https://api.openai.com/v1/chat/completions', {
31.             method: 'POST',
32.             headers: {
33.                 'Content-Type': 'application/json',
34.                 'Authorization': 'Bearer ' + apiKey
35.             },
36.             body: JSON.stringify({
37.                 model: "gpt-4o",
38.                 messages: [
39.                     { role: "system", content: "You are a helpful assistant that always only returns valid GeoJSON in response to user queries. Don't use too many vertices. Include somewhat detailed geometry and any attributes you think might be relevant. Include factual information. If you want to communicate text to the user, you may use a message property in the attributes of geometry objects. For compatibility with ArcGIS Pro, avoid multiple geometry types in the GeoJSON output. For example, don't mix points and polygons." },
40.                     { role: "user", content: prompt }
41.                 ],
42.                 max_tokens: 1024,
43.                 temperature: 0.5,
44.                 response_format: { "type": "json_object" }
45.             })
46.         });
47. 
48.         const data = await response.json();
49.         const geoJSON = JSON.parse(data.choices[0].message.content);
50.         res.status(200).json(geoJSON);
51.     } catch (error) {
52.         console.error('Error fetching from OpenAI:', error);
53.         res.status(500).json({ error: 'Failed to connect to OpenAI' });
54.     }
55. });
56. 
57. const PORT = process.env.PORT || 3000;
58. app.listen(PORT, () => {
59.     console.log(`Server running on port ${PORT}`);
60. });

