1. const { Tool } = require('../models/Tool');
2. const { Parameter } = require('../models/Parameter');
3. const { applyResult, getLayer } = require('../state');
4. 
5. /**
6.  * A tool tool for generating AI features.
7.  * Calls an API associated with an AI to interpret the user prompt.
8.  * Draws the features on the map.
9.  * 
10.  * Infers layer name, description, and fields from the prompt.
11.  * 
12.  * 
13.  */
14. 
15. class GenerateAIFeatures extends Tool {
16. 
17.     constructor() {    
18.         super("Generate AI Features", [
19.             new Parameter("Prompt","The prompt to generate AI features","text","")  
20.         ]);
21.     }
22. 
23.     async run(params) {
24.         const prompt = params['Prompt'];
25. 
26.         const response = await fetch('http://127.0.0.1:3000/api/ai_geojson', {
27.             method: 'POST',
28.             headers: {
29.                 'Content-Type': 'application/json'
30.             },
31.             body: JSON.stringify({ prompt })
32.         });
33.     
34.         if (!response.ok) {
35.             throw new Error(`AI request failed with status ${response.status}`);
36.         }
37. 
38.         const data = await response.json();
39.         data.toolMetadata = {
40.             name: this.name,
41.             params,
42.             timestamp: new Date().toISOString()
43.         };
44. 
45.         const res = applyResult({ addGeojson: data });
46. 
47.         if (res && res.ok) {
48.             for (const id of (res.added || [])) {
49.                 const addedLayer = getLayer(id);
50.                 if (!addedLayer || !addedLayer.feature || !addedLayer.feature.properties) continue;
51. 
52.                 const attributes = addedLayer.feature.properties;
53.                 let popupContent = "<table class='popupTable'>";
54.                 for (let key in attributes) {
55.                     popupContent += `<tr><td><b>${key.charAt(0).toUpperCase() + key.slice(1)}</b></td><td>${attributes[key]}</td></tr>`;
56.                 }
57.                 popupContent += "</table>";
58.                 if (typeof addedLayer.bindPopup === 'function') {
59.                     addedLayer.bindPopup(popupContent);
60.                 }
61.             }
62.             this.setStatus(0, 'AI features added to map.');
63.             return res;
64.         }
65. 
66.         this.setStatus(2, 'Failed to add AI features to map.');
67.     }
68.     
69.     
70. }
71. 
72. if (typeof module !== 'undefined' && module.exports) {
73.     module.exports = { GenerateAIFeatures };
74. } else {
75.     window.GenerateAIFeatures = GenerateAIFeatures;
76. }

