1. /* global L, turf */  // Tell ESLint that L and turf are global variables
2. 
3. const toolNames = ['RandomPointsTool', 'BufferTool', 'ExportTool', 'GenerateAIFeatures', 'GroupTool', 'AddDataTool']; // Keep this up to date
4. 
5. // Initialize the map
6. const map = L.map('map').setView([34, -117], 7);
7. L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
8.     maxZoom: 18,
9. }).addTo(map);
10. 
11. const drawnItems = new L.FeatureGroup();
12. map.addLayer(drawnItems);
13. 
14. document.getElementById('backButton').addEventListener('click', function() {
15.     document.getElementById('toolSelection').style.display = 'block';
16.     document.getElementById('toolDetails').classList.add('hidden');
17.     const statusMessage = document.getElementById('statusMessageText');
18.     statusMessage.textContent = "";
19.     document.getElementById('statusMessage').style.display = 'none';
20. });
21. 
22. // Set up an array to keep track of layers added to the TOC
23. const tocLayers = [];
24. const loadedTools = {}; // Object to store instantiated tools
25. 
26. const state = require('./state');
27. 
28. let drawControl = new L.Control.Draw({
29.     draw: {
30.         // Options here
31.     },
32.     edit: {
33.         featureGroup: drawnItems,
34.     },
35. });
36. map.addControl(drawControl);
37. 
38. // Function to get a tool instance by name
39. function getToolByName(name) {
40.     return loadedTools[name] || null;
41. }
42. 
43. // Function to update the DataContent div
44. function updateDataContent() {
45.     let content = document.getElementById('DataContent');
46.     // Ensure every layer has a stable id persisted into feature.properties.__id
47.     try {
48.         tocLayers.forEach((l) => state.ensureStableId(l));
49.     } catch (e) {
50.         // best-effort
51.     }
52. 
53.     let geoJsonData = JSON.stringify(drawnItems.toGeoJSON(), null, 2);
54.     content.innerHTML = `<code class="language-json">${Prism.highlight(geoJsonData, Prism.languages.json, 'json')}</code>`;
55. 
56.     const toolElement = document.getElementById('toolName');
57.     if (toolElement) {
58.         let toolname = toolElement.getAttribute('tool');
59.         let tool = getToolByName(toolname);
60.         if (tool) {
61.             tool.renderUI();
62.         }
63.     }
64. }
65. 
66. // Event listeners remain the same...
67. map.on(L.Draw.Event.CREATED, function (e) {
68.     let type = e.layerType,
69.         layer = e.layer;
70.     
71.     drawnItems.addLayer(layer);
72. 
73. 
74.     
75.     // Assign a stable id immediately.
76.     const stableId = state.registerLayer(layer);
77. 
78.     let message = '';
79.     if (type === 'marker') {
80.         message = `${stableId}`;
81.     } else {
82.         let vertices = layer.getLatLngs()[0];
83.         message = `${stableId} ${type} (${vertices.length} vertices)`;
84.     }
85. 
86.     addToToc(layer, message, type);
87.     updateDataContent();
88. });
89. 
90. map.on('draw:edited', function (e) {
91.     var layers = e.layers;
92.     layers.eachLayer(function (layer) {
93.         removeMessageForLayer(layer);
94.         const stableId = state.registerLayer(layer);
95. 
96.         // Markers don't have getLatLngs().
97.         let message = '';
98.         if (layer && typeof layer.getLatLngs === 'function') {
99.             let vertices = layer.getLatLngs()[0] || [];
100.             message = `${stableId} (${vertices.length} vertices)`;
101.         } else {
102.             message = `${stableId} (edited)`;
103.         }
104. 
105.         addToToc(layer, message);
106.     });
107.     updateDataContent();
108. });
109. 
110. map.on('draw:deleted', function (e) {
111.     var layers = e.layers;
112.     layers.eachLayer(function (layer) {
113.         if (layer && layer.__id) {
114.             // Let state.removeLayer handle removal from drawnItems for tracked layers
115.             state.removeLayer(layer.__id);
116.         } else {
117.             // Fall back to direct removal for untracked layers
118.             drawnItems.removeLayer(layer);
119.         }
120.         removeMessageForLayer(layer);
121.     });
122.     updateDataContent();
123. });
124. 
125. map.on('layeradd', function (e) {
126.     let layer = e.layer;
127.     // console.log(layer)
128.     // if layer has a feature.toolMetadata, add the layer to the TOC
129.     if (layer.hasOwnProperty('feature') && layer.feature.toolMetadata) {
130.         const stableId = state.registerLayer(layer, layer?.feature?.properties?.__id);
131.         let featureType = layer.feature.geometry.type;
132.         let message = `${stableId} ${featureType}`;
133.         addToToc(layer, message);
134.     }
135. });
136. let layerMessageMap = new Map();
137. 
138. function addToToc(layer, message, type) {
139.     // map types to fontawesome icons
140.     let iconMap = {
141.         marker: 'fa-solid fa-location-pin',
142.         rectangle: 'fa-solid fa-draw-polygon',
143.         circle: 'fa-solid fa-draw-polygon',
144.         polyline: 'fa-solid fa-draw-polygon',
145.         polygon: 'fa-solid fa-draw-circle',
146.     };
147.     const stableId = state.ensureStableId(layer);
148.     let messageId = `message-${stableId}`;
149.     document.getElementById('tocContent').innerHTML += `<p class="layer-message" id="${messageId}"><i class="${iconMap[type]}"></i> ${message}</p>`;
150.     if (Array.isArray(tocLayers) && !tocLayers.includes(layer)) {
151.         tocLayers.push(layer);
152.     }
153.     layerMessageMap.set(layer, messageId);
154. }
155. 
156. // Load tools dynamically and store them in the loadedTools object
157. document.addEventListener('DOMContentLoaded', () => {
158.     // Load tools synchronously since we're using require
159.     toolNames.forEach(name => {
160.         try {
161.             const ToolClass = require(`./tools/${name}`)[name];
162.             loadedTools[name] = new ToolClass();
163.         } catch (error) {
164.             console.error(`Failed to load tool: ${name}`, error);
165.         }
166.     });
167.     renderToolList(Object.values(loadedTools));
168. });
169. 
170. function renderToolList(tools) {
171.     const toolContainer = document.getElementById('toolSelection');
172.     tools.forEach(tool => {
173.         const toolDiv = document.createElement('div');
174.         toolDiv.className = 'tool';
175.         toolDiv.textContent = tool.name;
176.         toolDiv.addEventListener('click', () => {
177.             const toolNameElement = document.getElementById('toolName');
178.             if (toolNameElement) {
179.                 toolNameElement.setAttribute('tool', tool.constructor.name);
180.                 tool.renderUI();
181.             } else {
182.                 console.error("Element with ID 'toolName' not found.");
183.             }
184.         });
185.         toolContainer.appendChild(toolDiv);
186.     });
187. }
188. 
189. function removeMessageForLayer(layer) {
190.     let messageId = layerMessageMap.get(layer);
191.     if (messageId) {
192.         let messageElement = document.getElementById(messageId);
193.         // console.log(`removing ${messageElement}`);
194.         if (messageElement) {
195.             messageElement.remove();
196.         }
197.         layerMessageMap.delete(layer); // Remove association
198.     }
199. }
200. 
201. document.addEventListener('DOMContentLoaded', () => {
202.     updateDataContent();
203. });
204. 
205. // Export these before any requires to avoid circular dependencies
206. if (typeof module !== 'undefined' && module.exports) {
207.     module.exports = {
208.         map,
209.         drawnItems,
210.         tocLayers
211.     };
212. }
213. 
214.

