1. const stateModule = require('../state');
2. 
3. class Tool {
4.     constructor(name, parameters = [], description, map) {
5.         this.name = name;
6.         this.parameters = parameters;
7.         this.description = description;
8.         this.map = map;
9. 
10.         // Wrap the UI execution method in the constructor
11.         this.execute = this.reRenderOnExecute(this.execute.bind(this));
12. 
13.         // Messages to store status info
14.         this.statusMessage = `${name} executed successfully.`;
15.         this.statusCode = 0;
16. 
17.         //SUCCESS = 0;
18.         //GENERAL_ERROR = 1;
19.         //INVALID_INPUT = 2;
20.         //EXECUTION_FAILED = 3;
21.         //RESOURCE_NOT_FOUND = 4;
22.         //PERMISSION_DENIED = 5;
23.         //TIMEOUT = 6;
24.         //EXTERNAL_DEPENDENCY_ERROR = 7; 
25.     }
26. 
27.     // Method to set status and message
28.     setStatus(code, message) {
29.         this.statusCode = code;
30.         this.statusMessage = message;
31.     }
32. 
33.     // Method to get the current status
34.     getStatus() {
35.         return {
36.             code: this.statusCode,
37.             message: this.statusMessage
38.         };
39.     }
40. 
41.     // Describe this tool in a machine-readable way
42.     getSpec() {
43.         const params = (this.parameters || []).map((p) => ({
44.             name: p.name,
45.             description: p.description,
46.             type: p.type,
47.             defaultValue: p.defaultValue,
48.             options: p.options || undefined,
49.             min: p.min ?? undefined,
50.             max: p.max ?? undefined,
51.         }));
52.         return {
53.             key: this.constructor?.name || this.name,
54.             name: this.name,
55.             description: this.description || '',
56.             parameters: params,
57.         };
58.     }
59. 
60.     renderUI() {
61.         // console.log(`Rendering UI for ${this.constructor.name}`);
62.         const toolSelection = document.getElementById('toolSelection');
63.         const toolDetails = document.getElementById('toolDetails');
64.         const toolContent = document.getElementById('toolContent');
65. 
66.         toolSelection.style.display = 'none';
67.         toolDetails.classList.remove('hidden');
68.         toolContent.innerHTML = ''; // Clear existing content
69. 
70.         const toolName = document.createElement('h2');
71.         // add tool name to toolContent as attribute "tool"
72.         toolName.textContent = this.name;
73.         toolContent.appendChild(toolName);
74. 
75.         this.parameters.forEach(param => {
76.             const paramLabel = document.createElement('label');
77.             paramLabel.classList.add('param-label');
78.             paramLabel.textContent = `${param.name} `;
79.             paramLabel.htmlFor = `param-${param.name}`;
80. 
81.             let paramInput;
82.             let paramSlider;
83. 
84.             if (param.type === "dropdown") {
85.                 paramInput = document.createElement('select');
86.                 paramInput.id = `param-${param.name}`;
87.             } else if (param.type === "int" || param.type === "float") {
88.                 // Create container for number input and slider
89.                 const numberContainer = document.createElement('div');
90.                 numberContainer.classList.add('number-input-container');
91. 
92.                 // Create number input
93.                 paramInput = document.createElement('input');
94.                 paramInput.type = "number";
95.                 paramInput.id = `param-${param.name}`;
96.                 paramInput.value = param.defaultValue;
97.                 paramInput.step = param.type === "int" ? "1" : "0.1";
98.                 
99.                 // Add min/max if defined
100.                 if (param.min !== undefined) paramInput.min = param.min;
101.                 if (param.max !== undefined) paramInput.max = param.max;
102. 
103.                 // Create slider
104.                 paramSlider = document.createElement('input');
105.                 paramSlider.type = "range";
106.                 paramSlider.classList.add('param-slider');
107.                 paramSlider.value = param.defaultValue;
108.                 paramSlider.step = param.type === "int" ? "1" : "0.1";
109.                 
110.                 // Set min/max for slider
111.                 paramSlider.min = param.min !== undefined ? param.min : 0;
112.                 paramSlider.max = param.max !== undefined ? param.max : 100;
113. 
114.                 // Link slider and input
115.                 paramInput.addEventListener('input', (e) => {
116.                     paramSlider.value = e.target.value;
117.                 });
118.                 
119.                 paramSlider.addEventListener('input', (e) => {
120.                     paramInput.value = e.target.value;
121.                 });
122. 
123.                 numberContainer.appendChild(paramInput);
124.                 numberContainer.appendChild(paramSlider);
125.                 
126.                 // Modify the later append logic to use the container
127.                 toolContent.appendChild(paramLabel);
128.                 toolContent.appendChild(numberContainer);
129.                 toolContent.appendChild(document.createElement('br'));
130.                 return; // Use return instead of continue
131.             } else if (param.type === "boolean") {
132.                 paramInput = document.createElement('input');
133.                 paramInput.type = "checkbox";
134.                 paramInput.id = `param-${param.name}`;
135.                 paramInput.value = param.defaultValue;
136.             } else if (param.type === "text") {
137.                 paramInput = document.createElement('input');
138.                 paramInput.type = "text";
139.                 paramInput.id = `param-${param.name}`;
140.                 paramInput.value = param.defaultValue;
141.             } else if (param.type === "file") {
142.                 paramInput = document.createElement('input');
143.                 paramInput.type = "file";
144.                 paramInput.id = `param-${param.name}`;
145.             }
146.             
147.             // Common setup for non-number inputs
148.             if (paramInput) {
149.                 toolContent.appendChild(paramLabel);
150.                 toolContent.appendChild(paramInput);
151.                 toolContent.appendChild(document.createElement('br'));
152. 
153.                 paramInput.addEventListener('keydown', function(event) {
154.                     if (event.key === "Enter") {
155.                         event.preventDefault();
156.                         executeButton.click();
157.                     }
158.                 });
159.             }
160.         });
161. 
162.         // Create and append the Execute button after adding all parameters
163.         const executeButton = document.createElement('button');
164.         executeButton.textContent = 'Execute';
165.         executeButton.addEventListener('click', () => this.execute());
166.         toolContent.appendChild(executeButton);
167. 
168.     }
169. 
170.     collectParamsFromDOM() {
171.         const params = {};
172.         this.parameters.forEach(param => {
173.             const el = document.getElementById(`param-${param.name}`);
174.             if (!el) return;
175. 
176.             if (param.type === 'boolean') {
177.                 params[param.name] = !!el.checked;
178.             } else if (param.type === 'int') {
179.                 const value = parseInt(el.value, 10);
180.                 params[param.name] = Number.isNaN(value) ? param.defaultValue : value;
181.             } else if (param.type === 'float') {
182.                 const value = parseFloat(el.value);
183.                 params[param.name] = Number.isNaN(value) ? param.defaultValue : value;
184.             } else if (param.type === 'file') {
185.                 params[param.name] = el.files && el.files.length ? el.files[0] : null;
186.             } else {
187.                 params[param.name] = el.value;
188.             }
189.         });
190.         return params;
191.     }
192. 
193.     getExecutionContext() {
194.         return {
195.             map: this.map || (typeof stateModule.getMap === 'function' ? stateModule.getMap() : null),
196.             state: typeof stateModule.getState === 'function' ? stateModule.getState() : null,
197.             tool: this,
198.         };
199.     }
200. 
201.     async handleRunResult(result) {
202.         if (!result || !result.download) return;
203.         const { filename = 'download.json', mimeType = 'application/json', data = '' } = result.download;
204.         const blob = new Blob([typeof data === 'string' ? data : JSON.stringify(data)], { type: mimeType });
205.         const url = URL.createObjectURL(blob);
206.         const link = document.createElement('a');
207.         link.href = url;
208.         link.download = filename;
209.         link.click();
210.         URL.revokeObjectURL(url);
211.     }
212. 
213.     async execute() {
214.         const params = this.collectParamsFromDOM();
215.         const context = this.getExecutionContext();
216.         const result = await this.run(params, context);
217.         await this.handleRunResult(result);
218.         return result;
219.     }
220. 
221.     async run(_params, _context) {
222.         throw new Error(`${this.name} must implement run(params, context)`);
223.     }
224. 
225.     reRenderOnExecute(exec) {
226.         return async () => {
227.             const toolContent = document.getElementById('toolContent');
228.             
229.             // Start loading animation (pulsing background of toolContent div)
230.             toolContent.classList.add('pulsate');
231.             
232.             try {
233.                 await exec();
234.             } catch (error) {
235.                 // Set error status
236.                 this.setStatus(1, error?.message || 'Execution failed');
237.                 console.error('Error during execution:', error);
238.             } finally {
239.                 // Stop loading animation
240.                 toolContent.classList.remove('pulsate');
241.                 
242.                 // log the status
243.                 const status = this.getStatus();
244.                 const logStatus = status.code !== 0 ? console.warn : console.log;
245.                 logStatus("Status:", status.code, status.message);
246. 
247.                 // Update the status message in the UI
248.                 document.getElementById('statusMessage').style.display = 'block';
249. 
250.                 // remove whatever alert-* class is currently applied
251.                 const oldStatusMessage = document.getElementById('statusMessageText');
252.                 oldStatusMessage.classList.remove('alert-success', 'alert-danger');
